solution_code:
#include <iostream>
#include <string>

class Vehicle {
public:
    std::string brand;
    int year;
};

class Truck : public Vehicle {
public:
    int payload_kg;
};

int main() {
    Truck t;
    std::cin >> t.brand >> t.year >> t.payload_kg;
    std::cout << "Brand: " << t.brand << ", Year: " << t.year << "\n";
    std::cout << "Payload: " << t.payload_kg << " kg\n";
    return 0;
}

